import heapq
from collections import defaultdict

class Solution(object):
    def minimumTime(self, n, edges, disappear):
        adj = defaultdict(list)
        for u, v, w in edges:
            adj[u].append((v, w))
            adj[v].append((u, w))

        dist = [float('inf')] * n
        dist[0] = 0
        heap = [(0, 0)]  # (time, node)

        while heap:
            t, u = heapq.heappop(heap)
            if t > dist[u]:
                continue
            for v, w in adj[u]:
                new_t = t + w
                if new_t < dist[v] and new_t < disappear[v]:
                    dist[v] = new_t
                    heapq.heappush(heap, (new_t, v))

        return [d if d != float('inf') else -1 for d in dist]
